impl HashMap_str_i32 {
    fn is_empty(self) -> i32 {
        if self.len() == 0 {
            return 1
        }
        return 0
    }
}

impl HashMap_str_str {
    fn get_or_insert(self, key: string, value: string) -> string {
        return self.or_insert(key, value)
    }

    fn is_empty(self) -> i32 {
        if self.len() == 0 {
            return 1
        }
        return 0
    }
}
